-- In PostgreSQL (must be superuser or pg_extension owner)
CREATE EXTENSION IF NOT EXISTS vector;

-- Verify: list available operators
SELECT typname FROM pg_type WHERE typname = 'vector';

CREATE EXTENSION IF NOT EXISTS vector;

CREATE TABLE documents (
    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id   UUID NOT NULL,
    source_url  TEXT,
    lang        TEXT NOT NULL DEFAULT 'en',
    content     TEXT NOT NULL,
    embedding   VECTOR(1536),      -- OpenAI text-embedding-3-small dimension
    metadata    JSONB,             -- arbitrary per-doc attributes
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    indexed_at  TIMESTAMPTZ        -- set after embedding is stored
);

-- Relational indexes
CREATE INDEX doc_tenant        ON documents (tenant_id);
CREATE INDEX doc_tenant_lang   ON documents (tenant_id, lang);
CREATE INDEX doc_tenant_date   ON documents (tenant_id, created_at DESC);
-- JSONB metadata index for key lookups
CREATE INDEX doc_metadata      ON documents USING GIN (metadata jsonb_path_ops);
